public class TiposPrimitivos {
    public static void main(String[] args) {
        int idade = 25;
        long populacaoMundial = 8_100_000_000L; // 'L' obrigatório: passa do limite do int
        double preco = 19.90;
        char inicial = 'G';
        boolean ativo = true;

        // Autoboxing: int primitivo vira Integer objeto automaticamente
        Integer idadeObjeto = idade;

        // Unboxing: Integer objeto vira int primitivo automaticamente
        int idadeDeVolta = idadeObjeto;

        System.out.println(idade + " " + populacaoMundial + " " + preco);
    }
}

