codeExample:
String status = switch (codigo) {
    case 1 -> "Ativo";
    case 2 -> "Inativo";
    case 3, 4 -> "Pendente"; // múltiplos valores no mesmo case
    default -> "Desconhecido";
};

// switch com bloco, quando precisa de mais de uma linha
String mensagem = switch (diaDaSemana) {
    case 6, 7 -> "Fim de semana!";
    default -> {
        String base = "Dia útil";
        yield base + ", foco no trabalho"; // 'yield' retorna o valor do bloco
    }
};

codeExampleBad:
// switch tradicional: fall-through acidental por esquecer o break
switch (codigo) {
    case 1:
        System.out.println("Ativo");
        // faltou o break aqui!
    case 2:
        System.out.println("Inativo"); // executa TAMBÉM quando codigo == 1
        break;
    default:
        System.out.println("Desconhecido");
}

codeExample:
List<String> nomes = List.of("Ana", "Bruno", "Carla");

// for clássico: use quando precisar do índice
for (int i = 0; i < nomes.size(); i++) {
    System.out.println(i + ": " + nomes.get(i));
}

// while: quando a condição de parada não é um contador
int tentativas = 0;
while (tentativas < 3 && !conexaoEstabelecida()) {
    tentativas++;
}

// for-each: mais limpo quando só precisa do valor
for (String nome : nomes) {
    System.out.println(nome);
}

codeExampleBad:
List<String> nomes = new ArrayList<>(List.of("Ana", "Bruno", "Carla"));

// ConcurrentModificationException: não dá pra remover de uma lista
// enquanto o for-each está iterando sobre ela
for (String nome : nomes) {
    if (nome.equals("Bruno")) {
        nomes.remove(nome); // explode aqui
    }
}

codeExample:
public class Contador {
    public static void incrementar(int valor) {
        valor++; // só muda a cópia local
    }

    public static void adicionarItem(List<String> lista) {
        lista.add("novo"); // muta o objeto original — visível pra fora
    }

    public static void reatribuir(List<String> lista) {
        lista = new ArrayList<>(); // só muda a referência local, não afeta o chamador
    }

    // Overloading: mesmo nome, parâmetros diferentes
    public static int somar(int a, int b) { return a + b; }
    public static double somar(double a, double b) { return a + b; }
}

