codeExample:
public class Carro {
    private String cor;
    private String modelo;

    // Construtor: inicializa o estado do objeto
    public Carro(String cor, String modelo) {
        this.cor = cor;
        this.modelo = modelo;
    }

    public void acelerar() {
        System.out.println(modelo + " acelerando!");
    }

    public static void main(String[] args) {
        Carro meuCarro = new Carro("Preto", "Civic"); // objeto = instância da classe
        Carro carroDaVizinha = new Carro("Branco", "Onix"); // outro objeto, estado independente

        meuCarro.acelerar();
    }
}
